"use client";

import { cn } from "@/lib/utils";
import {
    LayoutGrid,
    List,
    Search,
    Filter,
    ArrowUpDown,
    Plus
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useState } from "react";
import {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
} from "@/components/ui/tooltip";

interface FloatingDockProps {
    className?: string;
    viewMode: "grid" | "list";
    setViewMode: (mode: "grid" | "list") => void;
    searchQuery: string;
    setSearchQuery: (query: string) => void;
    activeFilter: string;
    setActiveFilter: (filter: string) => void;
    onNewProject: () => void;
}

export function FloatingDock({
    className,
    viewMode,
    setViewMode,
    searchQuery,
    setSearchQuery,
    activeFilter,
    setActiveFilter,
    onNewProject
}: FloatingDockProps) {
    const [isSearchOpen, setIsSearchOpen] = useState(false);

    const filters = [
        { id: "ALL", label: "Tous" },
        { id: "GO", label: "Go" },
        { id: "EXPLORE", label: "Explore" },
        { id: "KILL", label: "Kill" },
    ];

    return (
        <div className={cn(
            "fixed bottom-8 left-1/2 -translate-x-1/2 z-50",
            "flex items-center gap-3 p-2 rounded-2xl",
            "bg-[#111]/80 backdrop-blur-2xl border border-white/10 shadow-[0_20px_40px_-10px_rgba(0,0,0,0.5)]",
            "transition-all duration-300 hover:scale-105",
            className
        )}>
            {/* View Toggles */}
            <div className="flex p-1 bg-white/5 rounded-xl border border-white/5">
                <TooltipProvider>
                    <Tooltip>
                        <TooltipTrigger asChild>
                            <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => setViewMode("grid")}
                                className={cn("h-10 w-10 rounded-lg", viewMode === "grid" ? "bg-white/10 text-white" : "text-[#5D5C5B] hover:text-white")}
                            >
                                <LayoutGrid className="w-5 h-5" />
                            </Button>
                        </TooltipTrigger>
                        <TooltipContent><p>Vue Grille</p></TooltipContent>
                    </Tooltip>
                </TooltipProvider>

                <TooltipProvider>
                    <Tooltip>
                        <TooltipTrigger asChild>
                            <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => setViewMode("list")}
                                className={cn("h-10 w-10 rounded-lg", viewMode === "list" ? "bg-white/10 text-white" : "text-[#5D5C5B] hover:text-white")}
                            >
                                <List className="w-5 h-5" />
                            </Button>
                        </TooltipTrigger>
                        <TooltipContent><p>Vue Liste</p></TooltipContent>
                    </Tooltip>
                </TooltipProvider>
            </div>

            <div className="w-px h-8 bg-white/10" />

            {/* Filters */}
            <div className="flex items-center gap-1 hidden md:flex">
                {filters.map((f) => (
                    <button
                        key={f.id}
                        onClick={() => setActiveFilter(f.id)}
                        className={cn(
                            "px-4 py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest transition-all duration-200",
                            activeFilter === f.id
                                ? "bg-white text-black shadow-glow"
                                : "text-[#5D5C5B] hover:bg-white/5 hover:text-white"
                        )}
                    >
                        {f.label}
                    </button>
                ))}
            </div>

            <div className="w-px h-8 bg-white/10 hidden md:block" />

            {/* Search */}
            <div className={cn(
                "relative flex items-center transition-all duration-300 overflow-hidden",
                isSearchOpen ? "w-64" : "w-10"
            )}>
                <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setIsSearchOpen(!isSearchOpen)}
                    className="absolute left-0 z-10 h-10 w-10 text-[#5D5C5B] hover:text-white"
                >
                    <Search className="w-5 h-5" />
                </Button>
                <Input
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="Rechercher..."
                    className={cn(
                        "h-10 border-none bg-white/5 text-white pl-10 pr-4 transition-all duration-300",
                        isSearchOpen ? "opacity-100 w-full" : "opacity-0 w-0 pointer-events-none"
                    )}
                    autoFocus={isSearchOpen}
                />
            </div>

            {/* Main Action */}
            <Button
                onClick={onNewProject}
                className="ml-2 h-12 w-12 rounded-xl bg-brand-primary text-white shadow-glow hover:bg-brand-primary/90 hover:scale-110 transition-all p-0"
            >
                <Plus className="w-6 h-6" />
            </Button>

        </div>
    );
}

